    50→static rapidjson::Value* field2json(const Message *msg, const FieldDescriptor *field,
    51→        rapidjson::Value::AllocatorType& allocator)
    52→{
    53→    const Reflection *ref = msg->GetReflection();
    54→    const bool repeated = field->is_repeated();
    55→
    56→    size_t array_size = 0;
    57→    if (repeated)
    58→    {
    59→        array_size = ref->FieldSize(*msg, field);
    60→    }
    61→    rapidjson::Value* json = NULL;
    62→    if (repeated)
    63→    {
    64→        json = new rapidjson::Value(rapidjson::kArrayType);
    65→    }
    66→    switch (field->cpp_type())
    67→    {
    68→        case FieldDescriptor::CPPTYPE_DOUBLE:
    69→            if (repeated)
    70→            {
    71→                for (size_t i = 0; i != array_size; ++i)
    72→                {
    73→                    double value = ref->GetRepeatedDouble(*msg, field, i);
    74→                    rapidjson::Value v(value);
    75→                    json->PushBack(v, allocator);
    76→                }
    77→            }
    78→            else
    79→            {
    80→                json = new rapidjson::Value(ref->GetDouble(*msg, field));
    81→            }
    82→            break;
    83→        case FieldDescriptor::CPPTYPE_FLOAT:
    84→            if (repeated)
    85→            {
    86→                for (size_t i = 0; i != array_size; ++i)
    87→                {
    88→                    float value = ref->GetRepeatedFloat(*msg, field, i);
    89→                    rapidjson::Value v(value);
    90→                    json->PushBack(v, allocator);
    91→                }
    92→            }
    93→            else
    94→            {
    95→                json = new rapidjson::Value(ref->GetFloat(*msg, field));
    96→            }
    97→            break;
    98→        case FieldDescriptor::CPPTYPE_INT64:
    99→            if (repeated)
   100→            {
   101→                for (size_t i = 0; i != array_size; ++i)
   102→                {
   103→                    int64_t value = ref->GetRepeatedInt64(*msg, field, i);
   104→                    rapidjson::Value v(value);
   105→                    json->PushBack(v, allocator);
   106→                }
   107→            }
   108→            else
   109→            {
   110→                json = new rapidjson::Value(ref->GetInt64(*msg, field));
   111→            }
   112→            break;
   113→        case FieldDescriptor::CPPTYPE_UINT64:
   114→            if (repeated)
   115→            {
   116→                for (size_t i = 0; i != array_size; ++i)
   117→                {
   118→                    uint64_t value = ref->GetRepeatedUInt64(*msg, field, i);
   119→                    rapidjson::Value v(value);
   120→                    json->PushBack(v, allocator);
   121→                }
   122→            }
   123→            else
   124→            {
   125→                json = new rapidjson::Value(ref->GetUInt64(*msg, field));
   126→            }
   127→            break;
   128→        case FieldDescriptor::CPPTYPE_INT32:
   129→            if (repeated)
   130→            {
   131→                for (size_t i = 0; i != array_size; ++i)
   132→                {
   133→                    int32_t value = ref->GetRepeatedInt32(*msg, field, i);
   134→                    rapidjson::Value v(value);
   135→                    json->PushBack(v, allocator);
   136→                }
   137→            }
   138→            else
   139→            {
   140→                json = new rapidjson::Value(ref->GetInt32(*msg, field));
   141→            }
   142→            break;
   143→        case FieldDescriptor::CPPTYPE_UINT32:
   144→            if (repeated)
   145→            {
   146→                for (size_t i = 0; i != array_size; ++i)
   147→                {
   148→                    uint32_t value = ref->GetRepeatedUInt32(*msg, field, i);
   149→                    rapidjson::Value v(value);
   150→                    json->PushBack(v, allocator);
   151→                }
   152→            }
   153→            else
   154→            {
   155→                json = new rapidjson::Value(ref->GetUInt32(*msg, field));
   156→            }
   157→            break;
   158→        case FieldDescriptor::CPPTYPE_BOOL:
   159→            if (repeated)
   160→            {
   161→                for (size_t i = 0; i != array_size; ++i)
   162→                {
   163→                    bool value = ref->GetRepeatedBool(*msg, field, i);
   164→                    rapidjson::Value v(value);
   165→                    json->PushBack(v, allocator);
   166→                }
   167→            }
   168→            else
   169→            {
   170→                json = new rapidjson::Value(ref->GetBool(*msg, field));
   171→            }
   172→            break;
   173→        case FieldDescriptor::CPPTYPE_STRING:
   174→            {
   175→                bool is_binary = field->type() == FieldDescriptor::TYPE_BYTES;
   176→                if (repeated)
   177→                {
   178→                    for (size_t i = 0; i != array_size; ++i)
   179→                    {
   180→                        std::string value = ref->GetRepeatedString(*msg, field, i);
   181→                        if (is_binary)
   182→                        {
   183→                            value = b64_encode(value);
   184→                        }
   185→                        rapidjson::Value v(value.c_str(), value.size(), allocator);
   186→                        json->PushBack(v, allocator);
   187→                    }
   188→                }
   189→                else
   190→                {
   191→                    std::string value = ref->GetString(*msg, field);
   192→                    if (is_binary)
   193→                    {
   194→                        value = b64_encode(value);
   195→                    }
   196→                    json = new rapidjson::Value(value.c_str(), value.size(), allocator);
   197→                }
   198→                break;
   199→            }
   200→        case FieldDescriptor::CPPTYPE_MESSAGE:
   201→            if (repeated)
   202→            {
   203→                for (size_t i = 0; i != array_size; ++i)
   204→                {
   205→                    const Message *value = &(ref->GetRepeatedMessage(*msg, field, i));
   206→                    rapidjson::Value* v = parse_msg(value, allocator);
   207→                    json->PushBack(*v, allocator);
   208→                    delete v;
   209→                }
   210→            }
   211→            else
   212→            {
   213→                const Message *value = &(ref->GetMessage(*msg, field));
   214→                json = parse_msg(value, allocator);
   215→            }
   216→            break;
   217→        case FieldDescriptor::CPPTYPE_ENUM:
   218→            if (repeated)
   219→            {
   220→                for (size_t i = 0; i != array_size; ++i)
   221→                {
   222→                    const EnumValueDescriptor* value = ref->GetRepeatedEnum(*msg, field, i);
   223→                    rapidjson::Value v(value->number());
   224→                    json->PushBack(v, allocator);
   225→                }
   226→            }
   227→            else
   228→            {
   229→                json = new rapidjson::Value(ref->GetEnum(*msg, field)->number());
   230→            }
   231→            break;
   232→        default:
   233→            break;
   234→    }
   235→    return json;
   236→}
