   238→static rapidjson::Value* parse_msg(const Message *msg, rapidjson::Value::AllocatorType& allocator)
   239→{
   240→    const Descriptor *d = msg->GetDescriptor();
   241→    if (!d)
   242→        return NULL;
   243→    size_t count = d->field_count();
   244→    rapidjson::Value* root = new rapidjson::Value(rapidjson::kObjectType);
   245→    if (!root)
   246→        return NULL;
   247→    for (size_t i = 0; i != count; ++i)
   248→    {
   249→        const FieldDescriptor *field = d->field(i);
   250→        if (!field)
   251→        {
   252→            delete root;
   253→            return NULL;
   254→        }
   255→
   256→        const Reflection *ref = msg->GetReflection();
   257→        if (!ref)
   258→        {
   259→            delete root;
   260→            return NULL;
   261→        }
   262→        const char *name = field->name().c_str();
   263→        if (field->is_optional() && !ref->HasField(*msg, field))
   264→        {
   265→            //do nothing
   266→        }
   267→        else
   268→        {
   269→            rapidjson::Value* field_json = field2json(msg, field, allocator);
   270→            root->AddMember(name, *field_json, allocator);
   271→            delete field_json;
   272→        }
   273→    }
   274→    return root;
   275→}
