   277→static int parse_json(const rapidjson::Value* json, Message* msg, std::string& err);
   278→static int json2field(const rapidjson::Value* json, Message* msg, const FieldDescriptor *field, std::string& err)
   279→{
   280→    const Reflection *ref = msg->GetReflection();
   281→    const bool repeated = field->is_repeated();
   282→    switch (field->cpp_type())
   283→    {
   284→        case FieldDescriptor::CPPTYPE_INT32:
   285→            {
   286→                if (json->GetType() != rapidjson::kNumberType)
   287→                {
   288→                    RETURN_ERR(ERR_INVALID_JSON, "Not a number");
   289→                }
   290→                if (repeated)
   291→                {
   292→                    ref->AddInt32(msg, field, (int32_t) json->GetInt());
   293→                }
   294→                else
   295→                {
   296→                    ref->SetInt32(msg, field, (int32_t) json->GetInt());
   297→                }
   298→                break;
   299→            }
   300→        case FieldDescriptor::CPPTYPE_UINT32:
   301→            {
   302→                if (json->GetType() != rapidjson::kNumberType)
   303→                {
   304→                    RETURN_ERR(ERR_INVALID_JSON, "Not a number");
   305→                }
   306→                if (repeated)
   307→                {
   308→                    ref->AddUInt32(msg, field, json->GetUint());
   309→                }
   310→                else
   311→                {
   312→                    ref->SetUInt32(msg, field, json->GetUint());
   313→                }
   314→                break;
   315→            }
   316→        case FieldDescriptor::CPPTYPE_INT64:
   317→            {
   318→                if (json->GetType() != rapidjson::kNumberType)
   319→                {
   320→                    RETURN_ERR(ERR_INVALID_JSON, "Not a number");
   321→                }
   322→                if (repeated)
   323→                {
   324→                    ref->AddInt64(msg, field, json->GetInt64());
   325→                }
   326→                else
   327→                {
   328→                    ref->SetInt64(msg, field, json->GetInt64());
   329→                }
   330→                break;
   331→            }
   332→        case FieldDescriptor::CPPTYPE_UINT64:
   333→            {
   334→                if (json->GetType() != rapidjson::kNumberType)
   335→                {
   336→                    RETURN_ERR(ERR_INVALID_JSON, "Not a number");
   337→                }
   338→                if (repeated)
   339→                {
   340→                    ref->AddUInt64(msg, field, json->GetUint64());
   341→                }
   342→                else
   343→                {
   344→                    ref->SetUInt64(msg, field, json->GetUint64());
   345→                }
   346→                break;
   347→            }
   348→        case FieldDescriptor::CPPTYPE_DOUBLE:
   349→            {
   350→                if (json->GetType() != rapidjson::kNumberType)
   351→                {
   352→                    RETURN_ERR(ERR_INVALID_JSON, "Not a number");
   353→                }
   354→                if (repeated)
   355→                {
   356→                    ref->AddDouble(msg, field, json->GetDouble());
   357→                }
   358→                else
   359→                {
   360→                    ref->SetDouble(msg, field, json->GetDouble());
   361→                }
   362→                break;
   363→            }
   364→        case FieldDescriptor::CPPTYPE_FLOAT:
   365→            {
   366→                if (json->GetType() != rapidjson::kNumberType)
   367→                {
   368→                    RETURN_ERR(ERR_INVALID_JSON, "Not a number");
   369→                }
   370→                if (repeated)
   371→                {
   372→                    ref->AddFloat(msg, field, json->GetDouble());
   373→                }
   374→                else
   375→                {
   376→                    ref->SetFloat(msg, field, json->GetDouble());
   377→                }
   378→                break;
   379→            }
   380→        case FieldDescriptor::CPPTYPE_BOOL:
   381→            {
   382→                if (json->GetType() != rapidjson::kTrueType && json->GetType() != rapidjson::kFalseType)
   383→                {
   384→                    RETURN_ERR(ERR_INVALID_JSON, "Not a bool");
   385→                }
   386→                bool v = json->GetBool();
   387→                if (repeated)
   388→                {
   389→                    ref->AddBool(msg, field, v);
   390→                }
   391→                else
   392→                {
   393→                    ref->SetBool(msg, field, v);
   394→                }
   395→                break;
   396→            }
   397→        case FieldDescriptor::CPPTYPE_STRING:
   398→            {
   399→                if (json->GetType() != rapidjson::kStringType)
   400→                {
   401→                    RETURN_ERR(ERR_INVALID_JSON, "Not a string");
   402→                }
   403→                const char* value = json->GetString();
   404→                uint32_t str_size = json->GetStringLength();
   405→                std::string str_value(value, str_size);
   406→                if (field->type() == FieldDescriptor::TYPE_BYTES)
   407→                {
   408→                    if (repeated)
   409→                    {
   410→                        ref->AddString(msg, field, b64_decode(str_value));
   411→                    }
   412→                    else
   413→                    {
   414→                        ref->SetString(msg, field, b64_decode(str_value));
   415→                    }
   416→                }
   417→                else
   418→                {
   419→                    if (repeated)
   420→                    {
   421→                        ref->AddString(msg, field, str_value);
   422→                    }
   423→                    else
   424→                    {
   425→                        ref->SetString(msg, field, str_value);
   426→                    }
   427→                }
   428→                break;
   429→            }
   430→        case FieldDescriptor::CPPTYPE_MESSAGE:
   431→            {
   432→                Message *mf = (repeated) ? ref->AddMessage(msg, field) : ref->MutableMessage(msg, field);
   433→                return parse_json(json, mf, err);
   434→            }
   435→        case FieldDescriptor::CPPTYPE_ENUM:
   436→            {
   437→                const EnumDescriptor *ed = field->enum_type();
   438→                const EnumValueDescriptor *ev = 0;
   439→                if (json->GetType() == rapidjson::kNumberType)
   440→                {
   441→                    ev = ed->FindValueByNumber(json->GetInt());
   442→                }
   443→                else if (json->GetType() == rapidjson::kStringType)
   444→                {
   445→                    ev = ed->FindValueByName(json->GetString());
   446→                }
   447→                else
   448→                    RETURN_ERR(ERR_INVALID_JSON, "Not an integer or string");
   449→                if (!ev)
   450→                    RETURN_ERR(ERR_INVALID_JSON, "Enum value not found");
   451→                if (repeated)
   452→                {
   453→                    ref->AddEnum(msg, field, ev);
   454→                }
   455→                else
   456→                {
   457→                    ref->SetEnum(msg, field, ev);
   458→                }
   459→                break;
   460→            }
   461→        default:
   462→            break;
   463→    }
   464→    return 0;
   465→}
