   467→static int parse_json(const rapidjson::Value* json, Message* msg, std::string& err)
   468→{
   469→    if (json->GetType() != rapidjson::kObjectType)
   470→    {
   471→        RETURN_ERR(ERR_INVALID_JSON, "Not an object");
   472→    }
   473→    const Descriptor *d = msg->GetDescriptor();
   474→    const Reflection *ref = msg->GetReflection();
   475→    if (!d || !ref)
   476→    {
   477→        RETURN_ERR(ERR_INVALID_PB, "Invalid pb object");
   478→    }
   479→    for (rapidjson::Value::ConstMemberIterator itr = json->MemberBegin(); itr != json->MemberEnd(); ++itr)
   480→    {
   481→        const char* name = itr->name.GetString();
   482→        const FieldDescriptor *field = d->FindFieldByName(name);
   483→        if (!field)
   484→            field = ref->FindKnownExtensionByName(name);
   485→        if (!field)
   486→            RETURN_ERR(ERR_UNKNOWN_FIELD, "Unknown field");
   487→        if (field->is_repeated())
   488→        {
   489→            if (itr->value.GetType() != rapidjson::kArrayType)
   490→                RETURN_ERR(ERR_INVALID_JSON, "Not array");
   491→            for (rapidjson::Value::ConstValueIterator ait = itr->value.Begin(); ait != itr->value.End(); ++ait)
   492→            {
   493→                int ret = json2field(ait, msg, field, err);
   494→                if (ret != 0)
   495→                {
   496→                    return ret;
   497→                }
   498→            }
   499→        }
   500→        else
   501→        {
   502→            int ret = json2field(&(itr->value), msg, field, err);
   503→            if (ret != 0)
   504→            {
   505→                return ret;
   506→            }
   507→        }
   508→    }
   509→    return 0;
   510→}
