   512→void json2string(const rapidjson::Value* json, std::string& str)
   513→{
   514→    rapidjson::StringBuffer buffer;
   515→    rapidjson::Writer<rapidjson::StringBuffer> writer(buffer);
   516→    json->Accept(writer);
   517→    str.append(buffer.GetString(), buffer.Size());
   518→}
   519→
   520→void pb2json(const Message* msg, std::string& str)
   521→{
   522→    rapidjson::Value::AllocatorType allocator;
   523→    rapidjson::Value* json = parse_msg(msg, allocator);
   524→    json2string(json, str);
   525→    delete json;
   526→}
