   528→rapidjson::Value* pb2jsonobject(const google::protobuf::Message* msg)
   529→{
   530→    rapidjson::Value::AllocatorType allocator;
   531→    return parse_msg(msg, allocator);
   532→}
   533→
   534→rapidjson::Value* pb2jsonobject(const google::protobuf::Message* msg, rapidjson::Value::AllocatorType& allocator)
   535→{
   536→    return parse_msg(msg, allocator);
   537→}
