   539→int json2pb(const std::string& json, google::protobuf::Message* msg, std::string& err)
   540→{
   541→    rapidjson::Document d;
   542→    d.Parse<0>(json.c_str());
   543→    if (d.HasParseError())
   544→    {
   545→        err = d.GetParseError();
   546→        return ERR_INVALID_JSON;
   547→    }
   548→    return jsonobject2pb(&d, msg, err);
   549→}
   550→
   551→int jsonobject2pb(const rapidjson::Value* json, google::protobuf::Message* msg, std::string& err)
   552→{
